Certainly! Writing a health check endpoint that verifies both remote services and database connections ensures your FastAPI application is fully operational. Here’s an example of how you can implement this:

### Step 1: Define the Health Check Route

First, define a route in your FastAPI application to perform health checks.

```python
from fastapi import APIRouter, status
from fastapi.responses import JSONResponse
import requests
from sqlalchemy.orm import sessionmaker
from sqlalchemy import create_engine
from sqlalchemy.exc import OperationalError

router = APIRouter()

# Example: Database connection string and remote service URLs
DATABASE_URL = "postgresql://user:password@localhost/dbname"
REMOTE_SERVICE_URLS = [
    "http://service1.example.com/health",
    "http://service2.example.com/health",
]

engine = create_engine(DATABASE_URL)
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

# Health check functions
def check_database():
    try:
        db = SessionLocal()
        db.execute("SELECT 1")
        db.close()
        return {"status": "ok", "message": "Database connection is live"}
    except OperationalError as e:
        return {"status": "error", "message": f"Database connection error: {str(e)}"}

def check_remote_service(url):
    try:
        response = requests.get(url, timeout=5)
        if response.status_code == 200:
            return {"status": "ok", "service_url": url}
        else:
            return {"status": "error", "service_url": url, "response_code": response.status_code}
    except requests.RequestException as e:
        return {"status": "error", "service_url": url, "message": str(e)}

def run_health_checks():
    health_results = {
        "database": check_database(),
        "remote_services": [],
    }

    for url in REMOTE_SERVICE_URLS:
        health_results["remote_services"].append(check_remote_service(url))

    return health_results

@router.get("/health", response_class=JSONResponse)
async def health_check():
    health_results = run_health_checks()

    if all(result["status"] == "ok" for result in [health_results["database"]] + health_results["remote_services"]):
        overall_status = "ok"
    else:
        overall_status = "error"

    return JSONResponse(
        status_code=status.HTTP_200_OK if overall_status == "ok" else status.HTTP_503_SERVICE_UNAVAILABLE,
        content={
            "status": overall_status,
            "details": health_results
        }
    )
```

